<?php declare(strict_types=1);
namespace SkyFi\System\Repositories;
use SkyFi\System\Contracts\BranchRepositoryContract;
final class PdoBranchRepository extends PdoSystemRepository implements BranchRepositoryContract { private array $allowed=['code','name','description','address_line_1','address_line_2','city','state','postal_code','country','phone','email','manager_user_id','timezone','status']; public function list(array $q): array { return $this->listRows('branches',$q,['code','name','city','email'],['status','city']); } public function find(int $id): array { return $this->findOne('branches',$id); } public function create(array $d,?int $u=null): array { return $this->insertRow('branches',$this->clean($d),$u); } public function update(int $id,array $d,?int $u=null): array { return $this->updateRow('branches',$id,$this->clean($d),$u); } public function delete(int $id): void { $this->softDeleteRow('branches',$id); } public function status(int $id,string $s,?int $u=null): array { return $this->statusRow('branches',$id,$s,$u); } private function clean(array $d): array { return array_intersect_key($d,array_flip($this->allowed)); }}
